-- USERS full reimport from Oracle export (single script)
DROP TABLE IF EXISTS syntec_users_staging;
CREATE TABLE syntec_users_staging LIKE syntec_users;
ALTER TABLE syntec_users_staging MODIFY created VARCHAR(20) NULL, MODIFY updated VARCHAR(20) NULL, MODIFY deleted_on VARCHAR(20) NULL, MODIFY photo_lastupd VARCHAR(20) NULL;
TRUNCATE TABLE syntec_users_staging;
UPDATE syntec_users_staging SET created = CASE WHEN created IS NULL OR created='' THEN NULL ELSE DATE_FORMAT(STR_TO_DATE(created,'%Y-%m-%d %H:%i:%s'),'%Y-%m-%d %H:%i:%s') END, updated = CASE WHEN updated IS NULL OR updated='' THEN NULL ELSE DATE_FORMAT(STR_TO_DATE(updated,'%Y-%m-%d %H:%i:%s'),'%Y-%m-%d %H:%i:%s') END, deleted_on = CASE WHEN deleted_on IS NULL OR deleted_on='' THEN NULL ELSE DATE_FORMAT(STR_TO_DATE(deleted_on,'%Y-%m-%d %H:%i:%s'),'%Y-%m-%d %H:%i:%s') END, photo_lastupd = CASE WHEN photo_lastupd IS NULL OR photo_lastupd='' THEN NULL ELSE DATE_FORMAT(STR_TO_DATE(photo_lastupd,'%Y-%m-%d %H:%i:%s'),'%Y-%m-%d %H:%i:%s') END;
ALTER TABLE syntec_users_staging MODIFY created DATETIME NULL, MODIFY updated DATETIME NULL, MODIFY deleted_on DATETIME NULL, MODIFY photo_lastupd DATETIME NULL;
TRUNCATE TABLE syntec_users;
SELECT COUNT(*) AS users_staging FROM syntec_users_staging;
SELECT COUNT(*) AS users_runtime FROM syntec_users;
SELECT user_id, username, created, updated, isactive, is_deleted_yn FROM syntec_users ORDER BY user_id LIMIT 50;
